"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperOrientation = "horizontal" | "vertical"

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("Stepper compound components must be used within a <Stepper>.")
  }
  return context
}

type StepperItemContextValue = {
  value: string
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error(
      "StepperTrigger, StepperTitle, and StepperDescription must be used within a <StepperItem>."
    )
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper
// ---------------------------------------------------------------------------

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: StepperOrientation
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-stretch",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

function StepperItem({
  value,
  disabled = false,
  completed = false,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = activeValue === value

  return (
    <StepperItemContext.Provider
      value={{ value, isActive, isCompleted: completed, isDisabled: disabled }}
    >
      <div
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={completed || undefined}
        data-disabled={disabled || undefined}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item group/stepper-item flex shrink-0",
          orientation === "horizontal"
            ? "flex-col items-center gap-2"
            : "flex-row items-start gap-4",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isActive, isCompleted, isDisabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-active={isActive || undefined}
      data-completed={isCompleted || undefined}
      disabled={isDisabled}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(value)}
      className={cn(
        "cn-stepper-trigger group/stepper-trigger inline-flex cursor-pointer items-center gap-2 text-sm font-medium transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive, isDisabled } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-active={isActive || undefined}
      data-disabled={isDisabled || undefined}
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive, isDisabled } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-active={isActive || undefined}
      data-disabled={isDisabled || undefined}
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

/**
 * Visual connector placed between <StepperItem> elements.
 *
 * Alignment note: the default margins (`mt-4` / `ms-4`) are calibrated
 * for step indicators that are `size-8` (2 rem). Override `className` when
 * using a different indicator size.
 */
function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="none"
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border transition-colors",
        orientation === "horizontal"
          ? "mt-4 h-px flex-1"
          : "ms-4 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperPanel
// ---------------------------------------------------------------------------

/**
 * Content panel associated with a step value. Only the panel whose `value`
 * matches the current active step is rendered. Pass `forceMount` to keep
 * the panel in the DOM while hidden (useful for forms with preserved state).
 */
