"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/radix/components/example"
import { Button } from "@/registry/bases/radix/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/registry/bases/radix/ui/card"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/radix/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="w-full max-w-4xl lg:grid-cols-1 2xl:max-w-4xl 2xl:grid-cols-1">
      <StepperBasic />
      <StepperVertical />
      <StepperWithDescriptions />
      <StepperWithContent />
      <StepperWizard />
      <StepperWithDisabled />
    </ExampleWrapper>
  )
}

// ---------------------------------------------------------------------------
// Shared step indicator helpers
// ---------------------------------------------------------------------------

function StepIndicator({
  step,
  isActive,
  isCompleted,
}: {
  step: number
  isActive: boolean
  isCompleted: boolean
}) {
  return (
    <span
      className={[
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        isCompleted
          ? "border-primary bg-primary text-primary-foreground"
          : isActive
            ? "border-primary bg-background text-primary"
            : "border-border bg-background text-muted-foreground",
      ].join(" ")}
    >
      {isCompleted ? (
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2.5"
          strokeLinecap="round"
          strokeLinejoin="round"
          className="size-4"
          aria-hidden="true"
        >
          <polyline points="20 6 9 17 4 12" />
        </svg>
      ) : (
        step
      )}
    </span>
  )
}

// ---------------------------------------------------------------------------
// Basic (horizontal)
// ---------------------------------------------------------------------------

function StepperBasic() {
  const steps = [
    { value: "step-1", label: "Account" },
    { value: "step-2", label: "Profile" },
    { value: "step-3", label: "Review" },
  ]

  return (
    <Example title="Basic">
      <Stepper defaultValue="step-2" className="w-full max-w-lg">
        {steps.map((step, index) => (
          <React.Fragment key={step.value}>
            {index > 0 && <StepperSeparator />}
            <StepItem value={step.value} stepNumber={index + 1} totalSteps={steps.length}>
              <StepperTrigger>
                <StepIndicatorSlot step={index + 1} />
                <StepperTitle>{step.label}</StepperTitle>
              </StepperTrigger>
            </StepItem>
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Vertical
// ---------------------------------------------------------------------------

function StepperVertical() {
  const steps = [
    { value: "step-1", label: "Account" },
    { value: "step-2", label: "Profile" },
    { value: "step-3", label: "Review" },
  ]

  return (
    <Example title="Vertical">
      <Stepper defaultValue="step-2" orientation="vertical" className="w-full max-w-xs">
        {steps.map((step, index) => (
          <React.Fragment key={step.value}>
            {index > 0 && <StepperSeparator />}
            <StepItem value={step.value} stepNumber={index + 1} totalSteps={steps.length}>
              <StepperTrigger>
                <StepIndicatorSlot step={index + 1} />
                <StepperTitle>{step.label}</StepperTitle>
              </StepperTrigger>
            </StepItem>
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// With Descriptions
// ---------------------------------------------------------------------------

function StepperWithDescriptions() {
  const steps = [
    {
      value: "step-1",
      label: "Account",
      description: "Email & password",
    },
    {
      value: "step-2",
      label: "Profile",
      description: "Name & avatar",
    },
    {
      value: "step-3",
      label: "Review",
      description: "Confirm details",
    },
  ]

  return (
    <Example title="With Descriptions">
      <Stepper defaultValue="step-1" className="w-full max-w-lg">
        {steps.map((step, index) => (
          <React.Fragment key={step.value}>
            {index > 0 && <StepperSeparator />}
            <StepItem value={step.value} stepNumber={index + 1} totalSteps={steps.length}>
              <StepperTrigger className="flex-col items-center gap-1 text-center">
                <StepIndicatorSlot step={index + 1} />
                <StepperTitle>{step.label}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </StepperTrigger>
            </StepItem>
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// With Content Panels
// ---------------------------------------------------------------------------

function StepperWithContent() {
  const [activeStep, setActiveStep] = React.useState("step-1")

  const steps = [
    { value: "step-1", label: "Account" },
    { value: "step-2", label: "Profile" },
    { value: "step-3", label: "Review" },
  ]

  const currentIndex = steps.findIndex((s) => s.value === activeStep)

  return (
    <Example title="With Content" containerClassName="col-span-full">
      <div className="w-full max-w-lg space-y-6">
        <Stepper
          value={activeStep}
          onValueChange={setActiveStep}
          className="w-full"
        >
          {steps.map((step, index) => (
            <React.Fragment key={step.value}>
              {index > 0 && <StepperSeparator />}
              <StepItem
                value={step.value}
                stepNumber={index + 1}
                totalSteps={steps.length}
                completed={index < currentIndex}
              >
                <StepperTrigger>
                  <StepIndicatorSlot step={index + 1} />
                  <StepperTitle>{step.label}</StepperTitle>
                </StepperTrigger>
              </StepItem>
            </React.Fragment>
          ))}
        </Stepper>

        <div className="rounded-xl border p-6 text-sm text-muted-foreground">
          <StepperPanel value="step-1" forceMount>
            {activeStep === "step-1" && (
              <p>
                Create your account by providing your email address and choosing
                a secure password.
              </p>
            )}
          </StepperPanel>
          <StepperPanel value="step-2" forceMount>
            {activeStep === "step-2" && (
              <p>
                Tell us a little about yourself. Add a display name and
                optionally upload a profile avatar.
              </p>
            )}
          </StepperPanel>
          <StepperPanel value="step-3" forceMount>
            {activeStep === "step-3" && (
              <p>
                Review your details before submitting. You can go back to any
                step to make changes.
              </p>
            )}
          </StepperPanel>
        </div>

        <div className="flex justify-between">
          <Button
            variant="outline"
            size="sm"
            disabled={currentIndex === 0}
            onClick={() => setActiveStep(steps[currentIndex - 1].value)}
          >
            Previous
          </Button>
          <Button
            size="sm"
            disabled={currentIndex === steps.length - 1}
            onClick={() => setActiveStep(steps[currentIndex + 1].value)}
          >
            Next
          </Button>
        </div>
      </div>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Wizard (full onboarding flow in a Card)
// ---------------------------------------------------------------------------

function StepperWizard() {
  const steps = [
    {
      value: "personal",
      label: "Personal Info",
      description: "Your basic details",
    },
    {
      value: "workspace",
      label: "Workspace",
      description: "Set up your space",
    },
    {
      value: "invite",
      label: "Invite Team",
      description: "Add collaborators",
    },
    {
      value: "done",
      label: "Done",
      description: "You're all set",
    },
  ]

  const [activeStep, setActiveStep] = React.useState(steps[0].value)
  const currentIndex = steps.findIndex((s) => s.value === activeStep)
  const isFirst = currentIndex === 0
  const isLast = currentIndex === steps.length - 1

  function goNext() {
    if (!isLast) setActiveStep(steps[currentIndex + 1].value)
  }

  function goPrev() {
    if (!isFirst) setActiveStep(steps[currentIndex - 1].value)
  }

  const panelContent: Record<string, React.ReactNode> = {
    personal: (
      <p className="text-sm text-muted-foreground">
        Enter your full name, job title, and time zone so your teammates know
        who you are.
      </p>
    ),
    workspace: (
      <p className="text-sm text-muted-foreground">
        Give your workspace a name and choose a URL slug. You can always change
        this later in settings.
      </p>
    ),
    invite: (
      <p className="text-sm text-muted-foreground">
        Invite colleagues by email. They will receive a link to join your
        workspace right away.
      </p>
    ),
    done: (
      <p className="text-sm text-muted-foreground">
        Everything is configured. Head to your dashboard to start collaborating
        with your team.
      </p>
    ),
  }

  return (
    <Example title="Wizard" containerClassName="col-span-full">
      <Card className="mx-auto w-full max-w-xl">
        <CardHeader>
          <CardTitle>Get started</CardTitle>
          <CardDescription>
            Step {currentIndex + 1} of {steps.length}
          </CardDescription>
        </CardHeader>

        <CardContent className="space-y-8">
          {/* Stepper header */}
          <Stepper
            value={activeStep}
            onValueChange={setActiveStep}
            className="w-full"
          >
            {steps.map((step, index) => (
              <React.Fragment key={step.value}>
                {index > 0 && <StepperSeparator />}
                <StepItem
                  value={step.value}
                  stepNumber={index + 1}
                  totalSteps={steps.length}
                  completed={index < currentIndex}
                >
                  <StepperTrigger className="flex-col items-center gap-1">
                    <StepIndicatorSlot step={index + 1} />
                    <StepperTitle className="hidden sm:block">
                      {step.label}
                    </StepperTitle>
                  </StepperTrigger>
                </StepItem>
              </React.Fragment>
            ))}
          </Stepper>

          {/* Step content */}
          <div className="min-h-[60px]">
            {steps.map((step) => (
              <StepperPanel key={step.value} value={step.value}>
                <div className="space-y-1">
                  <p className="font-medium">{step.label}</p>
                  {panelContent[step.value]}
                </div>
              </StepperPanel>
            ))}
          </div>
        </CardContent>

        <CardFooter className="flex justify-between">
          <Button variant="outline" onClick={goPrev} disabled={isFirst}>
            Back
          </Button>
          {isLast ? (
            <Button onClick={() => setActiveStep(steps[0].value)}>
              Start over
            </Button>
          ) : (
            <Button onClick={goNext}>Continue</Button>
          )}
        </CardFooter>
      </Card>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// With Disabled Steps
// ---------------------------------------------------------------------------

function StepperWithDisabled() {
  const steps = [
    { value: "step-1", label: "Account", disabled: false },
    { value: "step-2", label: "Profile", disabled: false },
    { value: "step-3", label: "Premium", disabled: true },
    { value: "step-4", label: "Review", disabled: false },
  ]

  return (
    <Example title="With Disabled">
      <Stepper defaultValue="step-2" className="w-full max-w-lg">
        {steps.map((step, index) => (
          <React.Fragment key={step.value}>
            {index > 0 && <StepperSeparator />}
            <StepItem
              value={step.value}
              stepNumber={index + 1}
              totalSteps={steps.length}
              disabled={step.disabled}
            >
              <StepperTrigger>
                <StepIndicatorSlot step={index + 1} />
                <StepperTitle>{step.label}</StepperTitle>
              </StepperTrigger>
            </StepItem>
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Internal helpers – thin wrappers used across examples
// ---------------------------------------------------------------------------

/**
 * Thin wrapper around <StepperItem> that reads its own active/completed state
 * through the StepperItem context so <StepIndicatorSlot> can react to it.
 */
function StepItem({
  value,
  stepNumber: _stepNumber,
  totalSteps: _totalSteps,
  ...rest
}: React.ComponentProps<typeof StepperItem> & {
  stepNumber: number
  totalSteps: number
}) {
  return <StepperItem value={value} {...rest} />
}

/**
 * Reads active / completed state from the nearest StepperItem context and
 * renders the numbered circle accordingly.
 */
function StepIndicatorSlot({ step }: { step: number }) {
  const { isActive, isCompleted } = useStepperItemState()
  return (
    <StepIndicator step={step} isActive={isActive} isCompleted={isCompleted} />
  )
}

/**
 * Hook that reads StepperItemContext without throwing so it can be used
 * inside helper components that render inside StepperItem children.
 */
function useStepperItemState() {
  const { useStepperItem: _unused, ...rest } = { useStepperItem: null }
  void rest
  // We import useStepperItem at the top of the file via the named export.
  // eslint-disable-next-line react-hooks/rules-of-hooks
  return useStepperItemStateInner()
}

import { useStepperItem } from "@/registry/bases/radix/ui/stepper"

function useStepperItemStateInner() {
  // eslint-disable-next-line react-hooks/rules-of-hooks
  return useStepperItem()
}

