// ---------------------------------------------------------------------------
// Wizard (full onboarding flow in a Card)
// ---------------------------------------------------------------------------

function StepperWizard() {
  const steps = [
    {
      value: "personal",
      label: "Personal Info",
      description: "Your basic details",
    },
    {
      value: "workspace",
      label: "Workspace",
      description: "Set up your space",
    },
    {
      value: "invite",
      label: "Invite Team",
      description: "Add collaborators",
    },
    {
      value: "done",
      label: "Done",
      description: "You're all set",
    },
  ]

  const [activeStep, setActiveStep] = React.useState(steps[0].value)
  const currentIndex = steps.findIndex((s) => s.value === activeStep)
  const isFirst = currentIndex === 0
  const isLast = currentIndex === steps.length - 1

  function goNext() {
    if (!isLast) setActiveStep(steps[currentIndex + 1].value)
  }

  function goPrev() {
    if (!isFirst) setActiveStep(steps[currentIndex - 1].value)
  }

  const panelContent: Record<string, React.ReactNode> = {
    personal: (
      <p className="text-sm text-muted-foreground">
        Enter your full name, job title, and time zone so your teammates know
        who you are.
      </p>
    ),
    workspace: (
      <p className="text-sm text-muted-foreground">
