function StepperWithContent() {
  const steps = [
    { value: "step-1", label: "Account" },
    { value: "step-2", label: "Profile" },
    { value: "step-3", label: "Review" },
  ]

  const [activeStep, setActiveStep] = React.useState("step-1")
  const currentIndex = steps.findIndex((s) => s.value === activeStep)

  return (
    <Example title="With Content" containerClassName="col-span-full">
      <div className="w-full max-w-lg space-y-6">
        <Stepper
          value={activeStep}
          onValueChange={setActiveStep}
          className="w-full"
        >
          {steps.map((step, index) => (
            <React.Fragment key={step.value}>
              {index > 0 && <StepperSeparator />}
              <StepperItem
                value={step.value}
                completed={index < currentIndex}
              >
                <StepperTrigger>
                  <StepIndicator step={index + 1} />
                  <StepperTitle>{step.label}</StepperTitle>
                </StepperTrigger>
              </StepperItem>
            </React.Fragment>
          ))}
        </Stepper>

        <div className="rounded-xl border p-6 text-sm text-muted-foreground">
          <StepperPanel value="step-1">
            <p>
              Create your account by providing your email address and choosing
              a secure password.
            </p>
          </StepperPanel>
          <StepperPanel value="step-2">
            <p>
              Tell us a bit about yourself. Add a display name and optionally
              upload a profile avatar.
            </p>
          </StepperPanel>
          <StepperPanel value="step-3">
            <p>
              Review your details before submitting. You can go back to any
              step to make changes.
            </p>
          </StepperPanel>
        </div>

        <div className="flex justify-between">
          <Button
            variant="outline"
            size="sm"
            disabled={currentIndex === 0}
            onClick={() => setActiveStep(steps[currentIndex - 1].value)}
          >
            Previous
          </Button>
          <Button
            size="sm"
            disabled={currentIndex === steps.length - 1}
            onClick={() => setActiveStep(steps[currentIndex + 1].value)}
          >
            Next
          </Button>
        </div>
      </div>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Wizard (full onboarding flow in a Card)
// ---------------------------------------------------------------------------

function StepperWizard() {
  const steps = [
    { value: "personal", label: "Personal Info", description: "Your basics" },
    { value: "workspace", label: "Workspace", description: "Set up space" },
    { value: "invite", label: "Invite Team", description: "Add teammates" },
    { value: "done", label: "Done", description: "All set!" },
  ]

  const [activeStep, setActiveStep] = React.useState(steps[0].value)
  const currentIndex = steps.findIndex((s) => s.value === activeStep)
  const isFirst = currentIndex === 0
  const isLast = currentIndex === steps.length - 1

  const panelContent: Record<string, React.ReactNode> = {
    personal: (
      <p>
        Enter your full name, job title, and time zone so your teammates know
        who you are.
      </p>
    ),
    workspace: (
      <p>
        Give your workspace a name and choose a URL slug. You can always update
        this later in settings.
      </p>
    ),
    invite: (
      <p>
        Invite colleagues by email. They will receive a link to join your
        workspace right away.
      </p>
    ),
    done: (
      <p>
        Everything is configured. Head to your dashboard to start collaborating
        with your team.
      </p>
    ),
  }

  return (
    <Example title="Wizard" containerClassName="col-span-full">
      <Card className="mx-auto w-full max-w-xl">
        <CardHeader>
          <CardTitle>Get started</CardTitle>
          <CardDescription>
            Step {currentIndex + 1} of {steps.length}
          </CardDescription>
        </CardHeader>

        <CardContent className="space-y-8">
          <Stepper
            value={activeStep}
            onValueChange={setActiveStep}
            className="w-full"
          >
            {steps.map((step, index) => (
              <React.Fragment key={step.value}>
                {index > 0 && <StepperSeparator />}
                <StepperItem
                  value={step.value}
                  completed={index < currentIndex}
                >
                  <StepperTrigger className="flex-col items-center gap-1">
                    <StepIndicator step={index + 1} />
                    <StepperTitle className="hidden sm:block text-xs">
                      {step.label}
                    </StepperTitle>
                  </StepperTrigger>
                </StepperItem>
              </React.Fragment>
            ))}
          </Stepper>

          <div className="min-h-[4rem] text-sm text-muted-foreground">
            {steps.map((step) => (
              <StepperPanel key={step.value} value={step.value}>
                <p className="mb-1 font-medium text-foreground">{step.label}</p>
                {panelContent[step.value]}
              </StepperPanel>
            ))}
          </div>
        </CardContent>

        <CardFooter className="flex justify-between">
          <Button variant="outline" onClick={() => !isFirst && setActiveStep(steps[currentIndex - 1].value)} disabled={isFirst}>
            Back
          </Button>
          {isLast ? (
            <Button onClick={() => setActiveStep(steps[0].value)}>
              Start over
            </Button>
          ) : (
            <Button onClick={() => setActiveStep(steps[currentIndex + 1].value)}>
              Continue
            </Button>
          )}
        </CardFooter>
      </Card>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// With Disabled Steps
// ---------------------------------------------------------------------------

function StepperWithDisabled() {
  const steps = [
    { value: "step-1", label: "Account", disabled: false },
    { value: "step-2", label: "Profile", disabled: false },
    { value: "step-3", label: "Premium", disabled: true },
    { value: "step-4", label: "Review", disabled: false },
  ]

  return (
    <Example title="With Disabled">
      <Stepper defaultValue="step-2" className="w-full max-w-lg">
        {steps.map((step, index) => (
          <React.Fragment key={step.value}>
            {index > 0 && <StepperSeparator />}
            <StepperItem value={step.value} disabled={step.disabled}>
              <StepperTrigger>
                <StepIndicator step={index + 1} />
                <StepperTitle>{step.label}</StepperTitle>
              </StepperTrigger>
            </StepperItem>
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
